ee:message.ee:set-payload:
%dw 2.0
output application/json
---
{
	wmsOrderId: "WMS-" ++ vars.originalPayload.poNumber,
	sourceSystem: "ERP",
	orderType: "PURCHASE_ORDER",
	header: {
		purchaseOrderNumber: vars.originalPayload.poNumber,
		vendorId: vars.originalPayload.supplierId,
		facilityId: vars.originalPayload.warehouseId,
		orderDate: vars.originalPayload.orderDate as String {format: "yyyy-MM-dd'T'HH:mm:ss'Z'"},
		orderStatus: vars.originalPayload.status default "NEW",
		expectedDeliveryDate: (vars.originalPayload.orderDate as DateTime + |P7D|) as String {format: "yyyy-MM-dd'T'HH:mm:ss'Z'"}
	},
	lineItems: vars.originalPayload.items map ((item, index) -> {
		lineNumber: index + 1,
		itemNumber: item.sku,
		orderedQuantity: item.quantity,
		unitOfMeasure: item.uom default "EA",
		receivedQuantity: 0,
		status: "PENDING"
	}),
	metadata: {
		correlationId: correlationId,
		processedAt: now() as String {format: "yyyy-MM-dd'T'HH:mm:ss.SSSZ"},
		sourceTransactionId: vars.originalPayload.poNumber
	}
}
